CREATE TABLE IF NOT EXISTS `{prefix}_forum_cats` ( `id` int(11) NOT NULL AUTO_INCREMENT, `parent_id` int(11) DEFAULT '0', `name` varchar(255) NOT NULL, `alt_name` varchar(255) NOT NULL, `description` varchar(500) DEFAULT '', `prefix_id` int(11) DEFAULT '0', `icon` varchar(100) DEFAULT 'fa-folder', `posi` int(11) DEFAULT '0', `topic_count` int(11) DEFAULT '0', `post_count` int(11) DEFAULT '0', `last_topic_id` int(11) DEFAULT '0', `last_post_id` int(11) DEFAULT '0', `permissions` varchar(500) DEFAULT 'all', `allowed_groups` varchar(500) DEFAULT '', `is_private` tinyint(1) DEFAULT '0', `read_groups` varchar(500) DEFAULT '', `write_groups` varchar(500) DEFAULT '', `require_approval` tinyint(1) DEFAULT '0', PRIMARY KEY (`id`), KEY `alt_name` (`alt_name`), KEY `parent_id` (`parent_id`), KEY `is_private` (`is_private`) ) ENGINE=InnoDB DEFAULT CHARSET={charset};
CREATE TABLE IF NOT EXISTS `{prefix}_forum_topics` ( `id` int(11) NOT NULL AUTO_INCREMENT, `cat_id` int(11) NOT NULL, `title` varchar(255) NOT NULL, `alt_name` varchar(255) NOT NULL, `description` varchar(500) DEFAULT '', `user_id` int(11) NOT NULL, `views` int(11) DEFAULT '0', `replies` int(11) DEFAULT '0', `is_pinned` tinyint(1) DEFAULT '0', `is_locked` tinyint(1) DEFAULT '0', `is_deleted` tinyint(1) DEFAULT '0', `is_approved` tinyint(1) NOT NULL DEFAULT '1', `last_bump_date` datetime DEFAULT NULL, `last_post_id` int(11) DEFAULT '0', `last_user_id` int(11) DEFAULT '0', `last_post_date` datetime DEFAULT NULL, `date` datetime NOT NULL, PRIMARY KEY (`id`), KEY `alt_name` (`alt_name`), KEY `cat_id` (`cat_id`), KEY `user_id` (`user_id`), KEY `last_post_date` (`last_post_date`), KEY `is_deleted` (`is_deleted`), KEY `is_approved` (`is_approved`), KEY `cat_id_deleted_pinned` (`cat_id`,`is_deleted`,`is_pinned`), FULLTEXT KEY `ft_title` (`title`) ) ENGINE=InnoDB DEFAULT CHARSET={charset};
CREATE TABLE IF NOT EXISTS `{prefix}_forum_posts` ( `id` int(11) NOT NULL AUTO_INCREMENT, `topic_id` int(11) NOT NULL, `user_id` int(11) NOT NULL, `text` mediumtext NOT NULL, `likes` int(11) DEFAULT '0', `dislikes` int(11) DEFAULT '0', `is_deleted` tinyint(1) DEFAULT '0', `is_approved` tinyint(1) NOT NULL DEFAULT '1', `ip` varchar(45) DEFAULT '', `date` datetime NOT NULL, `updated_at` datetime DEFAULT NULL, PRIMARY KEY (`id`), KEY `topic_id` (`topic_id`), KEY `user_id` (`user_id`), KEY `date` (`date`), KEY `topic_id_deleted` (`topic_id`,`is_deleted`), KEY `is_approved` (`is_approved`) ) ENGINE=InnoDB DEFAULT CHARSET={charset};
CREATE TABLE IF NOT EXISTS `{prefix}_forum_notifs` ( `id` int(11) NOT NULL AUTO_INCREMENT, `user_id` int(11) NOT NULL, `from_user` int(11) NOT NULL, `type` varchar(50) NOT NULL, `topic_id` int(11) NOT NULL, `post_id` int(11) DEFAULT '0', `payload` text DEFAULT NULL, `is_read` tinyint(1) DEFAULT '0', `date` datetime NOT NULL, PRIMARY KEY (`id`), KEY `user_id` (`user_id`), KEY `is_read` (`is_read`), KEY `topic_id` (`topic_id`), KEY `user_id_read_date` (`user_id`,`is_read`,`date`) ) ENGINE=InnoDB DEFAULT CHARSET={charset};
CREATE TABLE IF NOT EXISTS `{prefix}_forum_ranks` ( `id` int(11) NOT NULL AUTO_INCREMENT, `title` varchar(100) NOT NULL, `points` int(11) NOT NULL DEFAULT '0', `color` varchar(20) DEFAULT '#001f3f', `icon` varchar(100) DEFAULT 'fa-user', `badge_text` varchar(50) DEFAULT '', `for_group` int(11) NOT NULL DEFAULT '0', PRIMARY KEY (`id`), UNIQUE KEY `unique_title` (`title`), KEY `points` (`points`), KEY `for_group` (`for_group`) ) ENGINE=InnoDB DEFAULT CHARSET={charset};
CREATE TABLE IF NOT EXISTS `{prefix}_forum_subs` ( `id` int(11) NOT NULL AUTO_INCREMENT, `topic_id` int(11) NOT NULL, `user_id` int(11) NOT NULL, `date` datetime NOT NULL, PRIMARY KEY (`id`), UNIQUE KEY `user_topic` (`user_id`,`topic_id`), KEY `topic_id` (`topic_id`) ) ENGINE=InnoDB DEFAULT CHARSET={charset};
CREATE TABLE IF NOT EXISTS `{prefix}_forum_likes` ( `id` int(11) NOT NULL AUTO_INCREMENT, `post_id` int(11) NOT NULL, `user_id` int(11) NOT NULL, `type` enum('like','dislike') NOT NULL DEFAULT 'like', `date` datetime NOT NULL, PRIMARY KEY (`id`), UNIQUE KEY `user_post` (`user_id`,`post_id`), KEY `post_id` (`post_id`), KEY `post_id_type` (`post_id`,`type`) ) ENGINE=InnoDB DEFAULT CHARSET={charset};
CREATE TABLE IF NOT EXISTS `{prefix}_forum_readlog` ( `id` int(11) NOT NULL AUTO_INCREMENT, `user_id` int(11) NOT NULL, `topic_id` int(11) NOT NULL, `last_read_post` int(11) NOT NULL, `date` datetime NOT NULL, PRIMARY KEY (`id`), UNIQUE KEY `user_topic` (`user_id`,`topic_id`), KEY `topic_id` (`topic_id`) ) ENGINE=InnoDB DEFAULT CHARSET={charset};
CREATE TABLE IF NOT EXISTS `{prefix}_forum_edit_history` ( `id` int(11) NOT NULL AUTO_INCREMENT, `post_id` int(11) NOT NULL, `editor_id` int(11) NOT NULL, `old_text` mediumtext NOT NULL, `date` datetime NOT NULL, PRIMARY KEY (`id`), KEY `post_id` (`post_id`), KEY `editor_id` (`editor_id`) ) ENGINE=InnoDB DEFAULT CHARSET={charset};
