CREATE TABLE IF NOT EXISTS `{prefix}_forum_settings` ( `name` varchar(100) NOT NULL, `value` text NOT NULL, PRIMARY KEY (`name`) ) ENGINE=InnoDB DEFAULT CHARSET={charset};
