CREATE TABLE IF NOT EXISTS `{prefix}_forum_attachments` ( `id` int(11) NOT NULL AUTO_INCREMENT, `post_id` int(11) NOT NULL, `topic_id` int(11) NOT NULL, `user_id` int(11) NOT NULL, `filename` varchar(255) NOT NULL, `original_name` varchar(255) NOT NULL, `filesize` int(11) DEFAULT '0', `filetype` varchar(100) DEFAULT '', `mime_type` varchar(100) DEFAULT '', `file_hash` varchar(64) DEFAULT '', `is_image` tinyint(1) DEFAULT '0', `downloads` int(11) DEFAULT '0', `date` datetime NOT NULL, PRIMARY KEY (`id`), KEY `post_id` (`post_id`), KEY `topic_id` (`topic_id`), KEY `user_id` (`user_id`), KEY `file_hash` (`file_hash`) ) ENGINE=InnoDB DEFAULT CHARSET={charset};
CREATE TABLE IF NOT EXISTS `{prefix}_forum_bans` ( `id` int(11) NOT NULL AUTO_INCREMENT, `ip` varchar(45) NOT NULL DEFAULT '', `user_id` int(11) NOT NULL DEFAULT '0', `reason` text NOT NULL, `contact` varchar(255) NOT NULL DEFAULT '', `banned_by` int(11) NOT NULL DEFAULT '0', `created_at` int(11) NOT NULL DEFAULT '0', `expires_at` int(11) NOT NULL DEFAULT '0', PRIMARY KEY (`id`), KEY `ip` (`ip`), KEY `user_id` (`user_id`), KEY `expires_at` (`expires_at`) ) ENGINE=InnoDB DEFAULT CHARSET={charset};
CREATE TABLE IF NOT EXISTS `{prefix}_forum_flood` ( `id` int(11) NOT NULL AUTO_INCREMENT, `user_id` int(11) NOT NULL DEFAULT '0', `ip` varchar(45) NOT NULL DEFAULT '', `action` varchar(50) NOT NULL DEFAULT 'post', `last_action` int(11) NOT NULL DEFAULT '0', `count` int(11) NOT NULL DEFAULT '1', `blocked_until` int(11) NOT NULL DEFAULT '0', PRIMARY KEY (`id`), UNIQUE KEY `ip_action` (`ip`,`action`), UNIQUE KEY `user_action` (`user_id`,`action`), KEY `blocked_until` (`blocked_until`), KEY `idx_flood_ip_action_last` (`ip`, `action`, `last_action`), KEY `idx_flood_user_action_last` (`user_id`, `action`, `last_action`) ) ENGINE=InnoDB DEFAULT CHARSET={charset};
CREATE TABLE IF NOT EXISTS `{prefix}_forum_roles` ( `id` int(11) NOT NULL AUTO_INCREMENT, `cat_id` int(11) NOT NULL DEFAULT '0', `user_id` int(11) NOT NULL DEFAULT '0', `group_id` int(11) NOT NULL DEFAULT '0', `role` enum('admin','moderator','member','banned') NOT NULL DEFAULT 'member', PRIMARY KEY (`id`), UNIQUE KEY `cat_user` (`cat_id`,`user_id`), KEY `cat_id` (`cat_id`), KEY `user_id` (`user_id`), KEY `group_id` (`group_id`) ) ENGINE=InnoDB DEFAULT CHARSET={charset};
CREATE TABLE IF NOT EXISTS `{prefix}_conversations` ( `id` int(11) NOT NULL AUTO_INCREMENT, `subject` varchar(255) NOT NULL, `sender_id` int(11) NOT NULL, `recipient_id` int(11) NOT NULL, `created_at` int(11) NOT NULL, `updated_at` int(11) NOT NULL, PRIMARY KEY (`id`), KEY `sender_id` (`sender_id`), KEY `recipient_id` (`recipient_id`), KEY `updated_at` (`updated_at`) ) ENGINE=InnoDB DEFAULT CHARSET={charset};
CREATE TABLE IF NOT EXISTS `{prefix}_conversation_users` ( `conversation_id` int(11) NOT NULL, `user_id` int(11) NOT NULL, `last_read_at` int(11) DEFAULT NULL, `is_deleted` tinyint(1) DEFAULT '0', PRIMARY KEY (`conversation_id`,`user_id`), KEY `user_id` (`user_id`) ) ENGINE=InnoDB DEFAULT CHARSET={charset};
CREATE TABLE IF NOT EXISTS `{prefix}_conversations_messages` ( `id` int(11) NOT NULL AUTO_INCREMENT, `conversation_id` int(11) NOT NULL, `sender_id` int(11) NOT NULL, `content` text NOT NULL, `created_at` int(11) NOT NULL, PRIMARY KEY (`id`), KEY `conversation_id` (`conversation_id`), KEY `sender_id` (`sender_id`) ) ENGINE=InnoDB DEFAULT CHARSET={charset};
