CREATE TABLE IF NOT EXISTS `{prefix}_forum_flood` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL DEFAULT '0',
  `ip` varchar(45) NOT NULL DEFAULT '',
  `action` varchar(50) NOT NULL DEFAULT 'post',
  `last_action` int(11) NOT NULL DEFAULT '0',
  `count` int(11) NOT NULL DEFAULT '1',
  `blocked_until` int(11) NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  UNIQUE KEY `ip_action` (`ip`,`action`),
  UNIQUE KEY `user_action` (`user_id`,`action`),
  KEY `blocked_until` (`blocked_until`),
  KEY `idx_flood_ip_action_last` (`ip`, `action`, `last_action`),
  KEY `idx_flood_user_action_last` (`user_id`, `action`, `last_action`)
) ENGINE=InnoDB DEFAULT CHARSET={charset};

