  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_from_to` (`from_group`,`to_group`),
  KEY `from_group` (`from_group`),
  KEY `to_group` (`to_group`),
  KEY `is_active` (`is_active`)
) ENGINE=InnoDB DEFAULT CHARSET={charset};

-- Duplicate satırları temizle (unique key eklemeden önce varsa)
DELETE t1 FROM `{prefix}_forum_promotion_rules` t1
INNER JOIN `{prefix}_forum_promotion_rules` t2
WHERE t1.id > t2.id AND t1.from_group = t2.from_group AND t1.to_group = t2.to_group;

-- Mevcut kurulumda tablo varsa unique key'i ekle (yoksa hata vermez)
ALTER TABLE `{prefix}_forum_promotion_rules` ADD UNIQUE INDEX IF NOT EXISTS `unique_from_to` (`from_group`,`to_group`);

-- v1.2.0 Yeni sütunlar
ALTER TABLE `{prefix}_forum_cats` ADD COLUMN IF NOT EXISTS `require_approval` TINYINT(1) DEFAULT '0';
ALTER TABLE `{prefix}_forum_topics` ADD COLUMN IF NOT EXISTS `is_approved` TINYINT(1) NOT NULL DEFAULT '1';
ALTER TABLE `{userprefix}_users` ADD COLUMN IF NOT EXISTS `forum_total_likes` INT(11) DEFAULT '0';

INSERT IGNORE INTO `{prefix}_forum_promotion_rules` (`from_group`, `to_group`, `required_points`, `required_likes`, `required_posts`, `is_active`)
VALUES (4, 3, 100, 5, 10, 1);

INSERT IGNORE INTO `{prefix}_forum_promotion_rules` (`from_group`, `to_group`, `required_points`, `required_likes`, `required_posts`, `is_active`)
VALUES (3, 2, 500, 25, 50, 1);

DROP TABLE IF EXISTS `{prefix}_forum_pm`;

CREATE TABLE IF NOT EXISTS `{prefix}_forum_bans` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `ip` varchar(45) NOT NULL DEFAULT '',
  `user_id` int(11) NOT NULL DEFAULT '0',
  `reason` text NOT NULL,
  `contact` varchar(255) NOT NULL DEFAULT '',
  `banned_by` int(11) NOT NULL DEFAULT '0',
  `created_at` int(11) NOT NULL DEFAULT '0',
  `expires_at` int(11) NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `ip` (`ip`),
  KEY `user_id` (`user_id`),
  KEY `expires_at` (`expires_at`)
) ENGINE=InnoDB DEFAULT CHARSET={charset};

INSERT IGNORE INTO `{prefix}_forum_settings` (`name`, `value`) VALUES
('link_min_posts', '10'),
('link_min_points', '0'),
('forum_captcha', '0'),
('sticky_op', '1'),
('promotion_enabled', '1');

-- v1.2.0 Grup Öncelikli Rütbe Sistemi
ALTER TABLE `{prefix}_forum_ranks` ADD COLUMN IF NOT EXISTS `for_group` INT(11) NOT NULL DEFAULT '0' AFTER `badge_text`;
ALTER TABLE `{prefix}_forum_ranks` ADD INDEX IF NOT EXISTS `for_group` (`for_group`);

INSERT IGNORE INTO `{prefix}_forum_ranks` (`title`, `points`, `color`, `icon`, `badge_text`, `for_group`) VALUES
('Yönetici',   0, '#ef4444', 'fa-crown',          'Admin', 1),
('Editör',     0, '#f59e0b', 'fa-shield-halved',  'Editör', 2),
('Moderatör',  0, '#3b82f6', 'fa-shield',         'Mod', 3);

UPDATE `{prefix}_forum_ranks` SET `for_group` = 0 WHERE `title` = 'Moderatör' AND `for_group` = 0 AND `points` = 9999;

-- v1.2.0 Otomatik Migration: Mevcut kullanıcıları grup rütbeleriyle eşitle
UPDATE `{userprefix}_users` u
INNER JOIN `{prefix}_forum_ranks` r ON r.for_group = u.user_group AND r.for_group > 0
SET u.forum_rank_id = r.id;

