operation.replacecode:
switch ( $do ) {

case "forum" :
    $dle_module = "forum";
    $allow_active_news = false;
    include_once (DLEPlugins::Check(ENGINE_DIR . '/forum/init.php'));
    break;

    } elseif ($_POST['action'] == "forum") {
			        // 1. GÜVENLİK: CSRF Token Kontrolü
			        if (!isset($_POST['user_hash']) || !hash_equals((string)$dle_login_hash, (string)$_POST['user_hash'])) {
			            die("error");
			        }

			        // 2. Yetki ve Flood Koruması
			        if (!$is_logged) {
			            $author = $db->safesql($_IP);
			            $db->query("SELECT id FROM " . PREFIX . "_complaint WHERE `from`='{$author}'");
			            if ($db->num_rows() > 2) {
			                echo $lang['error_complaint_1'];
			                die();
			            }
			        } else {
			            $author = $db->safesql($member_id['name']);
			        }

			        $id = intval($_POST['id'] ?? 0);
			        if (!$id) die("error");

			        $text = trim($_POST['text'] ?? '');
			        if (empty($text)) {
			            echo $lang['error_complaint_4'];
			            die();
			        }

			        // 3. Limite Takılma Kontrolü
			        $row = $db->super_query("SELECT COUNT(*) as count FROM " . PREFIX . "_complaint WHERE text LIKE '[FORUM]%' AND `from`='{$author}'");
			        if ($row['count'] >= $config['max_complaints']) {
			            echo $lang['error_complaint_5'];
			            die();
			        }

			        // 4. Veritabanı Kontrolü
			        $post = $db->super_query("SELECT p.topic_id, t.title FROM " . PREFIX . "_forum_posts p LEFT JOIN " . PREFIX . "_forum_topics t ON t.id = p.topic_id WHERE p.id = '{$id}'");

			        if (!$post) die("error");

			        // 5. SEO Helper
			        if (!function_exists('forum_url')) {
			            include_once(DLEPlugins::Check(ENGINE_DIR . '/forum/forum.helper.php'));
			        }

			        $safe_topic_id = intval($post['topic_id']);
			        $raw_topic_link = function_exists('forum_url')
			            ? forum_url('forum_topic', ['newsid' => $safe_topic_id])
			            : $config['http_home_url'] . 'forum/topic/' . $safe_topic_id . '/';

			        $safe_title = htmlspecialchars($post['title'], ENT_QUOTES, 'UTF-8');
			        $safe_text  = htmlspecialchars($text, ENT_QUOTES, 'UTF-8');
			        $raw_complaint_text = "[FORUM] Mesaj ID: #{$id} | Konu: {$safe_title} | Link: {$raw_topic_link} | Neden: {$safe_text}";
			        $complaint_text = $db->safesql($raw_complaint_text);

			        // DLE 19 uyumlu complaint tablosu
			        $db->query("INSERT INTO " . PREFIX . "_complaint (`p_id`, `c_id`, `n_id`, `text`, `from`, `to`, `date`) VALUES ('0', '0', '0', '{$complaint_text}', '{$author}', '', '{$_TIME}')");

			        // 6. DLEPUSH
			        if (file_exists(ENGINE_DIR . '/classes/dlepush.class.php')) {
			            include_once(ENGINE_DIR . '/classes/dlepush.class.php');
			            $push = new DLEPush($db, $config);
			            $push->send(array(1), 'Yeni Forum Sikayeti', $author . ' bir mesaji sikayet etti: ' . $post['title'], $config['http_home_url'] . 'admin.php?mod=forum');
			        }

			        // 7. MAIL
			        if ($config['allow_complaint_mail']) {
			            include_once(DLEPlugins::Check(ENGINE_DIR . '/classes/mail.class.php'));
			            $mail_obj = new dle_mail($config);
			            $mail_obj->send($config['admin_mail'], "Yeni Forum Sikayeti: " . $post['title'], "Sitenizde yeni bir Forum Sikayeti yapildi:

			" . $raw_complaint_text . "

			Lutfen Yonetim Paneline girerek durumu inceleyiniz.");
			        }

			        if (ob_get_length()) ob_clean();
			        echo "ok";
			        exit;

// --- Forum Bilgileri Entegrasyonu (v1.1.1) ---
$tpl->set( '{forum-post-count}', isset($row['forum_post_count']) ? intval($row['forum_post_count']) : 0 );
$tpl->set( '{forum-points}', isset($row['forum_points']) ? intval($row['forum_points']) : 0 );

$forum_rank_html = '';
if(isset($row['forum_rank_id']) && intval($row['forum_rank_id']) > 0) {
        $fr_row = $db->super_query("SELECT title, color, icon FROM " . PREFIX . "_forum_ranks WHERE id = '" . intval($row['forum_rank_id']) . "'");
        if($fr_row) {
                $rc = isset($fr_row['color']) ? $fr_row['color'] : '#475569';
                $ri = isset($fr_row['icon']) ? $fr_row['icon'] : 'fa-user';
                $rt = isset($fr_row['title']) ? $fr_row['title'] : '';
                $forum_rank_html = '<span class="inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border" style="color:'.$rc.'; border-color:'.$rc.'30; background:'.$rc.'10"><i class="fa '.$ri.'"></i> '.htmlspecialchars($rt).'</span>';
        }
}
$tpl->set( '{forum-rank}', $forum_rank_html );
// --- Forum Bilgileri Entegrasyonu ---
